          <div class="onboarding-actions">
            ${this.step>0?'<button class="onboarding-btn onboarding-btn-secondary" id="onboarding-prev">← Back</button>':""}
            ${t?'<button class="onboarding-btn onboarding-btn-cta" id="onboarding-begin">Begin Observation</button>':'<button class="onboarding-btn onboarding-btn-primary" id="onboarding-next">Continue →</button>'}
          </div>
